INSERT INTO `base_template` VALUES ('1672501617122873346', '模版2', '<section style=\"margin: 0px 0px 24px; padding: 0px 10px; outline: 0px; max-width: 100%; background-color: #ffffff; font-size: 16px; line-height: 1.6; letter-spacing: 0px; word-break: break-word; font-family: Optima-Regular, Optima, PingFangSC-light, PingFangTC-light, \'PingFang SC\', Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif; box-sizing: border-box !important; overflow-wrap: break-word !important;\" data-tool=\"mdnice编辑器\" data-website=\"https://www.mdnice.com\" data-mpa-powered-by=\"yiban.io\">\n<p style=\"margin: 0px; padding: 8px 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; clear: both; min-height: 1em; line-height: 26px; text-align: justify;\" data-tool=\"mdnice编辑器\">本项目系统是是一款适用于搭建内部培训平台的开源系统，企业培训方案，致力于为更多企业机构搭建私有化内部培训平台。</p>\n<p style=\"margin: 0px; padding: 8px 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; clear: both; min-height: 1em; line-height: 26px; text-align: justify;\" data-tool=\"mdnice编辑器\">基于 Java + MySQL 开发，采用前后端分离模式，前台采用 React18 为核心框架，后台采用 SpringBoot3 为核心框架。</p>\n<h1 style=\"margin: 1.2em auto; padding: 0px; outline: 0px; font-size: 1.8em; max-width: 100%; color: #009688; text-align: center; border-bottom: 1px solid #009688; box-sizing: border-box !important; overflow-wrap: break-word !important;\" data-tool=\"mdnice编辑器\">功能明细</h1>\n<h3 style=\"margin: 0.6em auto; padding: 0px 0px 0px 10px; outline: 0px; font-size: 20px; max-width: 100%; border-left: 2px solid #009688; box-sizing: border-box !important; overflow-wrap: break-word !important;\" data-tool=\"mdnice编辑器\">学员端</h3>\n<ul class=\"list-paddingleft-1\" style=\"margin: 8px 0px; padding: 0px 0px 0px 25px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;\" data-tool=\"mdnice编辑器\">\n<li style=\"margin: 0px; padding: 0px; outline: 0p