-- ----------------------------
-- Table structure for blog_article
-- ----------------------------
DROP TABLE IF EXISTS `blog_article`;
CREATE TABLE `blog_article`  (
  `id` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '主键id',
  `title` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '标题',
  `cover` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '封面',
  `abstract_info` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '摘要',
  `content` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '内容',
  `menu_tab_type` tinyint(2) NULL DEFAULT NULL COMMENT '菜单tab类型',
  `technology_type` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '技术类型',
  `income_type` tinyint(2) NULL DEFAULT NULL COMMENT '收益方式（0:无；1：打赏；2：星球币）',
  `template_flag` tinyint(2) NULL DEFAULT NULL COMMENT '是否模板（0：否；1：是）',
  `publish_status` tinyint(2) NULL DEFAULT NULL COMMENT '发布状态（0：否；1：是）',
  `price` decimal(10, 2) NULL DEFAULT NULL COMMENT '价格(星球币)',
  `resource_id` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '资源ID',
  `del_flag` int(1) NULL DEFAULT 0 COMMENT '删除状态 0正常 1已删除',
  `description` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '描述',
  `create_by` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '文章表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of blog_article
-- ----------------------------
INSERT INTO `blog_article` VALUES ('1672235521711071233', '一款适用于搭建内部培训平台的系统，开源了！', 'temp/123_1687526949675.webp', '1111111', '<pre style=\"margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; color: #000000; letter-spacing: 0.544px;\">&nbsp;</pre>\n<section style=\"margin: 0px 0px 24px; padding: 0px 10px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; font-style: normal; font-variant-ligatures: normal; font-variant-caps: normal; font-weight: 400; orphans: 2; text-indent: 0px; text-transform: none; white-space: normal; widows: 2; word-spacing: 0px; -webkit-text-stroke-width: 0px; background-color: #ffffff; text-decoration-thickness: initial; text-decoration-style: initial; text-decoration-color: initial; font-size: 16px; color: black; line-height: 1.6; letter-spacing: 0px; word-break: break-word; text-align: left; font-family: Optima-Regular, Optima, PingFangSC-light, PingFangTC-light, \'PingFang SC\', Cambria, Cochin, Georgia, Times, \'Times New Roman\', serif;\" data-tool=\"mdnice编辑器\" data-website=\"https://www.mdnice.com\" data-mpa-powered-by=\"yiban.io\">\n<p style=\"margin: 0px; padding: 8px 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; clear: both; min-height: 1em; line-height: 26px; text-align: justify;\" data-tool=\"mdnice编辑器\">本项目系统是是一款适用于搭建内部培训平台的开源系统，企业培训方案，致力于为更多企业机构搭建私有化内部培训平台。</p>\n<p style=\"margin: 0px; padding: 8px 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; clear: both; min-height: 1em; line-height: 26px; text-align: justify;\" data-tool=\"mdnice编辑器\">基于 Java + MySQL 开发，采用前后端分离模式，前台采用 React18 为核心框架，后台采用 SpringBoot3 为核心框架。</p>\n<h1 style=\"margin: 1.2em auto; padding: 0px; outline: 0px; font-weight: bold; font-size: 1.8em; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; color: #009688; text-align: center; border-bottom: 1px solid #009688;\" data-tool=\"mdnice编辑器\">功能明细</h1>\n<h3 style=\"margin: 0.6em auto; padding: 0px 0px 0px 10px; outline: 0px; font-weight: bold; font-size: 20px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; border-left: 2px solid #009688;\" data-tool=\"mdnice编辑器\">学员端</h3>\n<ul class=\"list-paddingleft-1\" style=\"margin: 8px 0px; padding: 0px 0px 0px 25px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;\" data-tool=\"mdnice编辑器\">\n<li style=\"margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;\">\n<section style=\"margin: 5px 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; line-height: 26px; color: #010101;\">PC 端口</section>\n</li>\n<li style=\"margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;\">\n<section style=\"margin: 5px 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; line-height: 26px; color: #010101;\">移动端口（开发中）</section>\n</li>\n</ul>\n<h3 style=\"margin: 0.6em auto; padding: 0px 0px 0px 10px; outline: 0px; font-weight: bold; font-size: 20px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important; border-left: 2px solid #009688;\" data-tool=\"mdnice编辑器\">学员</h3>\n<ul class=\"list-paddingleft-1\" style=\"margin: 8px 0px; padding: 0px 0px 0px 25px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;\" data-tool=\"mdnice编辑器\">\n<li style=\"margin: 0px; padding: 0px; outline: 0px; max-width: 100%; box-sizing: border-box !important; overflow-wrap: break-word !important;\">\n<section style=\"margin: 5p