  `tenant_id` bigint(32) NULL DEFAULT NULL COMMENT '所属租户ID',
  `tenant_code` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '所属租户编码',
  `is_deleted` int(2) NULL DEFAULT 0 COMMENT '是否已删除（0为未删除；1为已删除。默认0）',
