DROP TABLE IF EXISTS `zb_project_gczj_menu`;
CREATE TABLE `zb_project_gczj_menu`  (
  `id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `rk_unique_key` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '入库唯一标识',
  `parent_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '上一节点ID',
  `project_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '项目ID',
  `file_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '附件ID',
  `number` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '编号',
  `name` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '项目名称',
  `menu_type` int(2) NULL DEFAULT NULL COMMENT '目录类型（1：项目；2：单项工程；3：单位工程；4：单位工程费用汇总；5：分部分项工程；6：措施项目；7：其他项目；8：规费税金；9：甲供材料；10：工料机汇总；11：工程特征信息；12：清单项目；13：分部工程；14：定额子目)',
  `attr` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '属性',
  `rule` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '规则',
  `unit` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '单位',
  `quantity` decimal(18, 2) NULL DEFAULT NULL COMMENT '工程量',
  `overhead_rate` decimal(18, 2) NULL DEFAULT NULL,
  `profit_rate` decimal(18, 2) NULL DEFAULT NULL,
  `price` decimal(18, 2) NULL DEFAULT NULL,
  `total` decimal(18, 2) NULL DEFAULT NULL,
  `labor` decimal(18, 2) NULL DEFAULT NULL,
  `labor_p` decimal(18, 2) NULL DEFAULT NULL,
  `material` decimal(18, 2) NULL DEFAULT NULL,
  `material_p` decimal(18, 2) NULL DEFAULT NULL,
  `main_material` decimal(18, 2) NULL DEFAULT NULL,
  `machine` decimal(18, 2) NULL DEFAULT NULL,
  `over_head` decimal(18, 2) NULL DEFAULT NULL,
  `profit` decimal(18, 2) NULL DEFAULT NULL,
  `appraisal` decimal(18, 2) NULL DEFAULT NULL,
  `calc_basis` decimal(18, 2) NULL DEFAULT NULL,
  `is_deleted` int(2) NOT NULL DEFAULT 0 COMMENT '是否已删除（0为未删除；1为已删除。默认0）',
  `creation_time` datetime NOT NULL COMMENT '创建时间',
  `creation_by` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建操作人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '最后更新时间',
  `update_by` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '最后更新操作人',
  `menu_attr` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '目录属性',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '工程造价解析-目录' ROW_FORMAT = DYNAMIC;

